What number is the arrow pointing to?
[tikz]
\begin{tikzpicture}
\draw[{Stealth}-{Stealth}] (-3.4,0)--(3.4,0);
\foreach \v in {-10,...,10} {\draw (0.3*\v,0.12)--(0.3*\v,-0.12);}
\foreach \v in {-10,-5,0,5,10} {\node[below] at (0.3*\v,-0.16) {$\v$};}
\draw[-{Stealth}] (-0.9,0.62)--(-0.9,0.14);
\end{tikzpicture}
[/tikz]

